// =============================================================================
// THE PROPOSAL TEMPLATE, EMBEDDED.
//
// This is Fern's real blank_bid_sheet.xlsx — logo, Arial 10, the 4-decimal unit
// price format, the SUM() formulas, the licence numbers, all six terms — encoded
// as base64 so it ships as CODE rather than as a file.
//
// Why: Next.js file-tracing pruned templates/ from the serverless bundle, so the
// route died with "File not found: /var/task/templates/..." — on Vercel only.
// Building fine locally and failing in production is the worst failure mode
// there is, so the dependency on file-tracing is removed entirely.
//
// TO UPDATE THE TEMPLATE: replace templates/proposal-template.xlsx and re-run
//   node scripts/embed-template.mjs
// which rewrites this file. The source .xlsx stays in the repo as the master.
// =============================================================================

export const PROPOSAL_TEMPLATE_B64 = "";

export function proposalTemplateBuffer() {
  return Buffer.from(PROPOSAL_TEMPLATE_B64, "base64");
}
